use std::collections::BTreeSet;

#[derive(Debug, PartialEq, Eq, PartialOrd, Ord, Clone)]
struct Interval {
    start: i32,
    end: i32,
}

fn find_overlapping_intervals(intervals: &[(i32, i32)]) -> BTreeSet<Interval> {
    let mut sorted_intervals = Vec::new();
    for &(start, end) in intervals { 
        sorted_intervals.push(Interval { start, end });
    }
    sorted_intervals.sort_by_key(|i| i.start);

    let mut overlaps = BTreeSet::new();
    if sorted_intervals.is_empty() {
        return overlaps;
    }

    overlaps.insert(sorted_intervals[0].clone());

    for i in 1..sorted_intervals.len() {
        let current = &sorted_intervals[i];
        let last_recorded = overlaps.last().unwrap();

        if current.start < last_recorded.end && current.end > last_recorded.start {
            overlaps.insert(Interval { start: std::cmp::min(current.start, last_recorded.start),
                                    end: std::cmp::max(current.end, last_recorded.end)
                                   });
        } else if current.start >= last_recorded.end {
            overlaps.insert(current.clone());
        }
    }
    overlaps
}

use std::collections::BTreeSet;

#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord)]
struct Interval {
    start: i64,
    end: i64,
}

struct IntervalManager {
    intervals: Vec<Interval>,
}

impl IntervalManager {
    fn new(intervals: Vec<Interval>) -> Self {
        Self { intervals }
    }

    fn add_interval(&mut self, interval: Interval) {
        self.intervals.push(interval);
    }

    fn find_overlapping_times(&self, query_start: i64, query_end: i64) -> Vec<Interval> {
        let query = Interval { start: query_start, end: query_end };
        let mut results = Vec::new();

        for interval in &self.intervals {
            if self.overlaps(interval, &query) {
                results.push(*interval);
            }
        }
        results
    }

    fn overlaps(&self, a: &Interval, b: &Interval) -> bool {
        a.start <= b.end && a.end >= b.start
    }
}

fn main() {
    let mut manager = IntervalManager::new(vec![]);
    manager.add_interval(Interval { start: 10, end: 20 });
    manager.add_interval(Interval { start: 5, end: 15 });
    manager.add_interval(Interval { start: 30, end: 40 });

    let query_start = 12;
    let query_end = 25;

    let overlaps = manager.find_overlapping_times(query_start, query_end);

    println!("Found {} overlapping intervals:", overlaps.len());
    for interval in overlaps {
        println!("{:?}", interval);
    }
}

