use std::collections::BTreeSet;

struct Interval(pub i64, pub i64);

impl PartialEq for Interval {
    fn eq(&self, other: &Self) -> bool {
        self.0 == other.0 && self.1 == other.1
    }
}

impl Eq for Interval {}

impl PartialOrd for Interval {
    fn partial_cmp(&self, other: &Self) -> Option<std::cmp::Ordering> {
        Some(self.cmp(other))
    }
}

impl Ord for Interval {
    fn cmp(&self, other: &Self) -> std::cmp::Ordering {
        match self.0.cmp(&other.0) {
            std::cmp::Ordering::Equal => self.1.cmp(&other.1),
            other => other,
        }
    }
}

fn check_for_overlap(intervals: Vec<Interval>) -> bool {
    let mut sorted_intervals = intervals;
    sorted_intervals.sort();

    if sorted_intervals.is_empty() {
        return false;
    }

    let mut current_end = sorted_intervals[0].1;

    for i in 1..sorted_intervals.len() {
        let next_start = sorted_intervals[i].0;
        let next_end = sorted_intervals[i].1;

        if next_start <= current_end {
            return true;
        }
        current_end = std::cmp::max(current_end, next_end);
    }

    false
}

use std::fs::File;
use std::io::{self, BufReader, BufRead};

struct Record {
    source_file: String,
    key: String,
    value: String,
}

fn main() -> io::Result<()> {
    let file_paths = vec!["data1.txt", "data2.txt"];
    let mut records: Vec<Record> = Vec::new();

    for path in file_paths {
        if !std::path::Path::new(path).exists() {
            continue;
        }

        let file = File::open(path)?;
        let reader = BufReader::new(file);

        for line in reader.lines() {
            let line_str = line?;
            if line_str.contains(":PATTERN") {
                let parts: Vec<&str> = line_str.split(":PATTERN").collect();
                if parts.len() == 2 {
                    let source = path.to_string();
                    let key_value_pair = parts[1];

                    let mut key_parts = key_value_pair.split(":::") .take(2).collect::<Vec<&str>>();
                    if key_parts.len() == 2 {
                        let key = key_parts[0].to_string();
                        let value = key_parts[1].trim().to_string();
                        records.push(Record { source_file: source, key, value });
                    }
                }
            }
        }
    }

    for record in records {
        println!("Found Record - Source: {}, Key: {}, Value: {}", record.source_file, record.key, record.value);
    }

    Ok(())
}
